'use client'
import {useRouter,useSearchParams } from "next/navigation";
import { useState } from "react";

export default function PriceFilter() {
  const  router = useRouter();
  const search_params = useSearchParams()

  const minLimit = 0;
  const maxLimit = 5000;

  const minQuery = Number(search_params.get("min_price")) || minLimit;
  const maxQuery = Number(search_params.get("max_price")) || maxLimit;

  const [min, setMin] = useState(minQuery);
  const[max,setMax] = useState(maxQuery);

  const handleMaxChange = (e) =>{

    const value = e?.target?.value
    
    setMax(value)
  }

  const handleMinChange = (e) => {
    const value = e?.target?.value;

    setMin(value)
  }

  function applyFilter(){
  const query = new URLSearchParams(search_params.toString())
    query.delete("min_price");
    query.delete("max_price");

    query.set("min_price",min);
    query.set("max_price",max);

    
    router.replace(`?${query.toString()}`, { scroll: false });
  }
  function clearFilter(){
    const query = new URLSearchParams(search_params.toString())
      query.delete("min_price");
      query.delete("max_price");
      
      setMin(minLimit)
      setMax(maxLimit)
      router.replace(`?${query.toString()}`, { scroll: false });
    }
  return (
    <div className="w-72 bg-gray-200 rounded-md p-4 mt-3 flex flex-col gap-4">
      
      {/* Title */}
      <h2 className="text-sm font-semibold text-gray-800">
        By Price
      </h2>

      {/* Price Inputs */}
      <div className="flex items-center gap-2">
        
        {/* Min Price */}
        <div className="relative flex-1 min-w-0">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm">
            $
          </span>
          <input
            type="number"
            onChange={handleMinChange}
            value={min}
            className="w-full pl-7 pr-2 py-2 rounded-lg border border-gray-200 bg-white text-sm text-gray-700 focus:outline-none focus:ring-1 focus:ring-gray-300"
          />
        </div>

        {/* Max Price */}
        <div className="relative flex-1 min-w-0">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm">
            $
          </span>
          <input
            type="number"
            value={max}
            onChange={handleMaxChange}
            className="w-full pl-7 pr-2 py-2 rounded-lg border border-gray-200 bg-white text-sm text-gray-700 focus:outline-none focus:ring-1 focus:ring-gray-300"
          />
        </div>

      </div>

      {/* Buttons at Bottom */}
      <div className="flex gap-2 mt-2">
  
  {/* Go Button */}
  <button
    type="button"
    onClick={applyFilter}
    className="flex-1 py-2 bg-black text-white text-sm rounded-lg hover:bg-gray-800 transition"
  >
    Go
  </button>

  {/* Clear Button */}
  <button
    type="button"
    onClick={clearFilter}
    className="flex-1 py-2 bg-white border border-gray-300 text-sm rounded-lg text-gray-700 hover:bg-gray-100 transition"
  >
    Clear
  </button>

</div>
    </div>
  );
} 